package controller; import javax.swing.*; import util.JapandiTheme; import service.impl.*; import model.CareRecord;
public class AddCareRecordFrame extends BaseFrame{ public AddCareRecordFrame(){super("新增照護紀錄",420,640);JPanel p=root();p.add(header("新增照護紀錄"));JTextField type=new JTextField("用藥");JTextField date=new JTextField("2026/07/02");JTextField time=new JTextField("08:00");JTextField content=new JTextField("已服藥");JTextField note=new JTextField("早餐後");JTextField[] fs={type,date,time,content,note};for(int i=0;i<fs.length;i++){fs[i].setBounds(50,110+i*58,310,42);p.add(fs[i]);}JButton save=JapandiTheme.primary("儲存");save.setBounds(50,425,310,44);save.addActionListener(e->{new CareRecordServiceImpl().add(new CareRecord(0,type.getText(),date.getText(),time.getText(),content.getText(),note.getText()));JOptionPane.showMessageDialog(this,"已新增照護紀錄");dispose();});p.add(save);} }